INSERT OR IGNORE INTO stories (title, slug, lang, series_key, episode_number, category_id, body, ai_generated, qc_status, source_format, status, confidence_score, related_ayah_id, pdf_ebook_id, published_at)
SELECT 'Episode 1: Dzulkifli, Among the Patient', 'kisah-dzulkifli-01-termasuk-orang-sabar', 'en', 'kisah-dzulkifli', 1, 1, 'Prophet Dzulkifli (Dhul-Kifl) is among the servants of Allah whose name is immortalized in the Qur''an, even though his life story is not told in detail. He is mentioned alongside noble prophets as a model of patience. Allah said, "And [mention] Isma''il and Idris and Dhul-Kifl; all were of the patient. And We admitted them into Our mercy. Indeed, they were of the righteous" (Qur''an 21:85-86).

Notice the two qualities Allah attaches to him in this brief ayah: "of the patient" (minas-shabirin) and "of the righteous" (minas-shalihin). Those two are already the highest praise for a servant — for patience is the root of every virtue, and righteousness is its fruit.

Allah places Dhul-Kifl beside Isma''il and Idris — two great prophets. Being named in a single line with them shows Dhul-Kifl''s high rank before Allah, even though the details of his struggle were not narrated to us.

Reflection: a servant''s worth before Allah is not measured by how famous his story is, but by his patience and righteousness. Many righteous people are unremembered by men, yet honored before Allah.

Source & Note: this episode rests purely on the Qur''an, 21:85-86 (text and translation from the quran-json dataset). The name "Dhul-Kifl" appears only twice in the Qur''an (here and 38:48), both times as brief praise without any narrative detail.', 0, 'qc_pending', 'ai_original', 'published', 1.0,
  (SELECT id FROM ayah WHERE surah_id = 21 AND number = 85), NULL, datetime('now');

